package com.ichi2.anki.preferences

import com.ichi2.anki.cardviewer.ViewerCommand
import org.junit.Test
import org.junit.Assert.fail
import org.xmlpull.v1.XmlPullParser
import org.xmlpull.v1.XmlPullParserFactory
import java.io.InputStreamReader

/**
 * Test to ensure all ViewerCommand entries are defined in the preferences_controls.xml file.
 * This is called out in the discussion that commands should be defined in XML (not
 * programmatically) so they can be grouped into categories.
 */
class ControlsSettingsTest {

    @Test
    fun ensureAllCommandsDefinedInXml() {
        // List of all command preference keys that should be in the XML
        val commands = ViewerCommand.values().map { it.preferenceKey }.toSet()

        // Parse the XML file to extract all defined control preferences
        val parser = XmlPullParserFactory.newInstance().newPullParser()
        val inputStream = javaClass.classLoader!!.getResourceAsStream("xml/preferences_controls.xml")
            ?: fail("Could not find preferences_controls.xml in resources")

        parser.setInput(InputStreamReader(inputStream))
        val definedKeys = mutableListOf<String>()

        var eventType = parser.eventType
        while (eventType != XmlPullParser.END_DOCUMENT) {
            if (eventType == XmlPullParser.START_TAG && 
                parser.name == "com.ichi2.preferences.ControlPreference") {
                val keyAttr = parser.getAttributeValue(null, "android:key")
                if (keyAttr != null) {
                    definedKeys.add(keyAttr)
                }
            }
            eventType = parser.next()
        }

        // Find any commands that are not defined in the XML
        val undefinedCommands = commands - definedKeys.toSet()

        if (undefinedCommands.isNotEmpty()) {
            fail("The following ViewerCommand preferences are not defined in preferences_controls.xml:\n" +
                undefinedCommands.joinToString("\n") + 
                "\n\nAll commands must be defined in the XML file to ensure proper grouping.")
        }
    }
}"}

