package com.ichi2.anki.preferences

import androidx.preference.Preference
import com.ichi2.anki.R
import com.ichi2.anki.cardviewer.ViewerCommand
import com.ichi2.anki.reviewer.MappableBinding.Companion.toPreferenceString
import com.ichi2.preferences.ControlPreference

class ControlsSettingsFragment : SettingsFragment() {
    override val preferenceResource: Int
        get() = R.xml.preferences_controls
    override val analyticsScreenNameConstant: String
        get() = "prefs.controls"

    override fun initSubscreen() {
        // Preferences are now defined in XML, so we just need to ensure
        // default values are set for any control preferences that haven't been customized
        setDefaultValues()
    }

    /**
     * Sets default values for ControlPreference items if they haven't been customized yet.
     * This ensures that even though preferences are defined in XML, each control preference
     * gets its appropriate default bindings.
     */
    private fun setDefaultValues() {
        for (command in ViewerCommand.values()) {
            val preference = findPreference<ControlPreference>(command.preferenceKey)
            if (preference != null) {
                // Set default value for the preference
                preference.setDefaultValue(command.defaultValue.toPreferenceString())
            }
        }
    }

    /**
     * DO NOT USE THIS METHOD ANYMORE.
     * Control preferences are now defined in XML (preferences_controls.xml)
     * instead of being added programmatically.
     *
     * @deprecated This method is kept for reference but should not be used.
     * Control preferences are now defined in preferences_controls.xml in groups.
     */
    @Deprecated(
        "Use XML preference definitions instead",
        replaceWith = ReplaceWith("preferences are now defined in preferences_controls.xml")
    )
    fun addAllControlPreferencesToCategory(category: PreferenceCategory) {
        // This method is no longer needed as preferences are defined in XML
        for (command in ViewerCommand.values()) {
            val preference = ControlPreference(category.context).apply {
                setTitle(command.resourceId)
                key = command.preferenceKey
                setDefaultValue(command.defaultValue.toPreferenceString())
            }
            category.addPreference(preference)
        }
    }
}","file_path":"/project/AnkiDroid/src/main/java/com/ichi2/anki/preferences/ControlsSettingsFragment.kt"}

